import{_ as a,o as l,c as i,a2 as t}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Call Logs","description":"","frontmatter":{},"headers":[],"relativePath":"features/call-logs.md","filePath":"features/call-logs.md"}'),s={name:"features/call-logs.md"};function o(r,e,c,n,d,h){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="call-logs" tabindex="-1">Call Logs <a class="header-anchor" href="#call-logs" aria-label="Permalink to &quot;Call Logs&quot;">​</a></h1><p>Call Logs provide a searchable history of calls handled by Callytics. You can filter by direction, status, and search terms, then open a specific call to understand what happened from start to finish.</p><p>Each call can show the execution trace of the flow, including every step the caller visited. This makes it easier to answer questions like which menu option was pressed, whether a queue timed out, or where a call was transferred.</p><p>For quality troubleshooting, Callytics scores RTP metrics and presents them with clear labels and color-coded badges. Active calls can also be followed from a live execution panel, and SIP-related issues can be opened directly in SIP Capture using the call&#39;s Call-ID.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Searchable paginated call history</li><li>Direction filters</li><li>Status filters</li><li>Clear filters action</li><li>Per-call execution trace showing every node visited</li><li>RTP quality scoring with MOS, jitter, packet loss, and RTT</li><li>Color-coded quality badges</li><li>Quality drawer with plain-English labels</li><li>Deep link to SIP Capture filtered by Call-ID</li><li>Live execution panel for active calls</li></ul>',6)])])}const f=a(s,[["render",o]]);export{u as __pageData,f as default};
